import { useEffect, useState } from "react";
import AnnonceCard from "../components/AnnonceCard";
import FiltresBarre from "../components/FiltresBarre";
import MapView from "../components/MapView";
import { annoncesApi, favorisApi } from "../services/api";

const Recherche = () => {
  const [filters, setFilters] = useState({ zone: "", type_bien: "", type_offre: "", prix_min: "", prix_max: "", page: 1, limit: 20 });
  const [data, setData] = useState({ total: 0, data: [] });

  const load = () => annoncesApi.list(filters).then((res) => setData(res.data)).catch(() => setData({ total: 0, data: [] }));
  useEffect(() => { load(); }, [filters.page]);

  const save = (id) => favorisApi.add(id).catch(() => null);

  return (
    <div className="space-y-4">
      <FiltresBarre filters={filters} setFilters={setFilters} />
      <button className="bg-primary text-white px-4 py-2 rounded" onClick={load}>Appliquer les filtres</button>
      <p>{data.total} résultats</p>
      <div className="grid lg:grid-cols-3 gap-4">
        {data.data.map((annonce) => <AnnonceCard key={annonce.id} annonce={annonce} onSave={save} />)}
      </div>
      <MapView points={data.data.map((a) => ({ ...a, lat: a.localisation?.coordinates?.[1], lon: a.localisation?.coordinates?.[0] }))} />
      <div className="flex gap-2">
        <button className="px-3 py-1 border rounded" onClick={() => setFilters({ ...filters, page: Math.max(1, filters.page - 1) })}>Précédent</button>
        <button className="px-3 py-1 border rounded" onClick={() => setFilters({ ...filters, page: filters.page + 1 })}>Suivant</button>
      </div>
    </div>
  );
};

export default Recherche;
